package com.syan.netonej.http.entity.ca;

import com.syan.netonej.common.dict.ResponseFormat;
import com.syan.netonej.common.json.JSONException;
import com.syan.netonej.common.json.JSONObject;
import com.syan.netonej.exception.NetonejException;
import com.syan.netonej.http.entity.NetoneResponse;


public class CertificateResponse extends NetoneResponse {
    private String signatureCert;

    private String encryptionCert;

    private String encryptionKey;

    public CertificateResponse(NetoneResponse response) throws NetonejException {
        super(response.getStatusCode());
        if(response != null && response.getStatusCode() == 200){
            String result = response.getResult();
            if(response.getFormat() == ResponseFormat.TEXT){
                try {
                    //result示例值：
                    //{"signatureCert":"",
                    // "encryptionCert":"",
                    // "encryptionKey":""}
                    JSONObject json = new JSONObject(result);
                    this.setSignatureCert(json.getString("signatureCert")); // 使用optString避免JSONException;
                    this.setEncryptionCert(json.getString("encryptionCert"));
                    this.setEncryptionKey(json.optString("encryptionKey", null));
                } catch (JSONException e) {
                    throw new RuntimeException(e);
                }
            }
        }
    }

    public String getSignatureCert() {
        return signatureCert;
    }

    public void setSignatureCert(String signatureCert) {
        this.signatureCert = signatureCert;
    }

    public String getEncryptionCert() {
        return encryptionCert;
    }

    public void setEncryptionCert(String encryptionCert) {
        this.encryptionCert = encryptionCert;
    }

    public String getEncryptionKey() {
        return encryptionKey;
    }

    public void setEncryptionKey(String encryptionKey) {
        this.encryptionKey = encryptionKey;
    }
}
